from flask import Flask, render_template, request, url_for, redirect, flash
from werkzeug.security import generate_password_hash, check_password_hash
# We'll use flask-login for the user session handling
from flask_login import login_user, logout_user, current_user, LoginManager

app = Flask(__name__)
app.config['SECRET_KEY'] = 'Thisisasecret!'
# This is your database object/session link here
login_manager = LoginManager()
login_manager.init_app(app)

class User():
    def __init__(self, id, name, password):
        self.id = id 
        self.password = password
        self.name = name

# Mock users for now
users = [User(1, 'admin', generate_password_hash('admin')), User(2, 'user', generate_password_hash('user'))]
username_table = {u.name: u for u in users}
uid_table = {u.id: u for u in users}

@app.route('/login', methods=['GET', 'POST'])
def login():
    if current_user.is_authenticated:
        return redirect(url_for('home'))  # Redirect to home page
    if request.method == "POST":
        username = request.form['username']
        password = request.form['password']
        remember = request.form.get('remember')
        
        user = username_table.get(username)
    
        # Username doesn't exist or password is incorrect
        if not user or not check_password_hash(user.password, password): 
            flash('Please check your login details and try again.', 'error')
            return redirect(url_for('login'))  # If authentication fails, back to login page
        
        login_user(user, remember=remember)
        return redirect(url_for('home'))  # Login successfully
    return render_template('login.html')  

@app.route('/logout')
def logout():
    logout_user()
    return redirect(url_for('login'))
    
# Flask-Login helper functions
@login_manager.user_loader
def load_user(id):
  return uid_table.get(int(id))

if __name__ == '__main__':
   app.run()